    primes = get_primes(limit)

    rads = [1] * (limit + 1)
    for p in primes:
        for i in range(p, limit + 1, p):
            rads[i] *= p

    total_sum = 0

    # We need to find a, b, c such that:
    # a < b, a + b = c, c < limit
    # gcd(a, b) = 1
    # rad(a) * rad(b) * rad(c) < c

    for c in range(1, limit):
        rad_c = rads[c]
        if rad_c >= c:
            continue

        # rad(a) * rad(b) * rad_c < c
        # rad(a) * rad(b) < c / rad_c

        limit_ab = c / rad_c

        for a in range(1, c // 2 + 1):
            b = c - a
            if a >= b:
                break

            # rad(a) * rad(b) < limit_ab
            if rads[a] * rads[b] < limit_ab:
                if math.gcd(a, b) == 1:
                    total_sum += c

    return total_sum

