def get_order(n):
    # We want the smallest k such that 10^k = 1 (mod 9n)
    m = 9 * n

    # The order of 10 modulo m divides phi(m).
    # This is still not quite right.
    # Let's use the property that the order of 10 modulo m
    # is the smallest k such that 10^k = 1 (mod m).

    # We can compute the order of 10 modulo m by:
    # 1. Find the prime factorization of phi(m).
    # 2. The order k is a divisor of phi(m).
    # 3. For each prime factor p of phi(m), check if 10^(phi(m)/p) = 1 (mod m).
    #    If it is, then the order divides phi(m)/p.

    # This is much faster than the loop!

    def get_phi(n):
        result = n
        p = 2
        while p * p <= n:
            if n % p == 0:
                while n % p == 0:
                    n //= p
                result -= result // p
            p += 1
        if n > 1:
            result -= result // n
        return result

    phi = get_phi(m)

    # Find all divisors of phi
    divs = []
